#!/usr/bin/env node
/**
 * Drive Reel Publisher
 * 
 * PM2 cron job that reads pre-generated Ghost videos from Google Drive
 * and publishes them as Instagram Reels via Graph API.
 * 
 * The videos are generated by ghost-reel-factory.py (Colab T4 pipeline)
 * and stored in Google Drive: /GhostAI-Reels/queue/
 * 
 * After publishing, videos are moved to /GhostAI-Reels/posted/
 * 
 * Usage:
 *   node scripts/drive-reel-publisher.js              # Publish next scheduled video
 *   node scripts/drive-reel-publisher.js --dry-run    # Preview without posting
 *   node scripts/drive-reel-publisher.js --list       # List queued videos
 * 
 * Environment:
 *   GOOGLE_SERVICE_ACCOUNT_KEY  - Path to Google service account JSON key
 *   GDRIVE_QUEUE_FOLDER_ID      - Google Drive folder ID for /GhostAI-Reels/queue/
 *   GDRIVE_POSTED_FOLDER_ID     - Google Drive folder ID for /GhostAI-Reels/posted/
 *   INSTAGRAM_GRAPH_USER_ID     - Instagram user ID
 *   INSTAGRAM_GRAPH_TOKEN       - Instagram Graph API access token
 */

import dotenv from 'dotenv';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { google } from 'googleapis';

dotenv.config();

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const CACHE_DIR = path.join(__dirname, '..', '.drive-cache');
const LOG_DIR = path.join(__dirname, '..', 'logs');

const QUEUE_FOLDER_ID = process.env.GDRIVE_QUEUE_FOLDER_ID || '';
const POSTED_FOLDER_ID = process.env.GDRIVE_POSTED_FOLDER_ID || '';
const SERVICE_ACCOUNT_KEY = process.env.GOOGLE_SERVICE_ACCOUNT_KEY || '';

const IG_USER_ID = process.env.INSTAGRAM_GRAPH_USER_ID || '';
const IG_TOKEN = process.env.INSTAGRAM_GRAPH_TOKEN || process.env.FACEBOOK_PAGE_ACCESS_TOKEN || '';
const IG_API_BASE = 'https://graph.facebook.com/v24.0';

const DRY_RUN = process.argv.includes('--dry-run');
const LIST_ONLY = process.argv.includes('--list');

for (const dir of [CACHE_DIR, LOG_DIR]) {
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
}

function log(msg) {
    const ts = new Date().toISOString();
    const line = `[${ts}] ${msg}`;
    console.log(line);
    const logFile = path.join(LOG_DIR, `drive-publisher-${new Date().toISOString().slice(0, 10)}.log`);
    fs.appendFileSync(logFile, line + '\n');
}

function sleep(ms) {
    return new Promise(r => setTimeout(r, ms));
}

// ── Google Drive Auth ────────────────────────────────────────────────────────

async function getDriveClient() {
    let keyData;

    if (SERVICE_ACCOUNT_KEY && fs.existsSync(SERVICE_ACCOUNT_KEY)) {
        keyData = JSON.parse(fs.readFileSync(SERVICE_ACCOUNT_KEY, 'utf-8'));
    } else if (process.env.GOOGLE_SERVICE_ACCOUNT_JSON) {
        keyData = JSON.parse(process.env.GOOGLE_SERVICE_ACCOUNT_JSON);
    } else {
        throw new Error('No Google service account credentials found. Set GOOGLE_SERVICE_ACCOUNT_KEY or GOOGLE_SERVICE_ACCOUNT_JSON.');
    }

    const auth = new google.auth.GoogleAuth({
        credentials: keyData,
        scopes: ['https://www.googleapis.com/auth/drive'],
    });

    return google.drive({ version: 'v3', auth });
}

// ── Queue Operations ─────────────────────────────────────────────────────────

async function listQueuedVideos(drive) {
    const today = new Date().toISOString().slice(0, 10);

    const res = await drive.files.list({
        q: `'${QUEUE_FOLDER_ID}' in parents and mimeType='video/mp4' and trashed=false`,
        fields: 'files(id, name, size, createdTime)',
        orderBy: 'name',
    });

    const videos = (res.data.files || []).map(f => {
        // Parse scheduled date from filename: YYYY-MM-DD_post_N_pillar.mp4
        const match = f.name.match(/^(\d{4}-\d{2}-\d{2})_/);
        return {
            id: f.id,
            name: f.name,
            size: f.size,
            scheduledDate: match ? match[1] : 'unknown',
            isToday: match ? match[1] === today : false,
        };
    });

    return videos;
}

async function getMetadata(drive, videoFile) {
    // Look for matching .json metadata file
    const metaName = videoFile.name.replace('.mp4', '.json');

    const res = await drive.files.list({
        q: `'${QUEUE_FOLDER_ID}' in parents and name='${metaName}' and trashed=false`,
        fields: 'files(id, name)',
    });

    if (!res.data.files?.length) return null;

    const metaFile = res.data.files[0];
    const content = await drive.files.get(
        { fileId: metaFile.id, alt: 'media' },
        { responseType: 'text' },
    );

    try {
        return { ...JSON.parse(content.data), metaFileId: metaFile.id };
    } catch {
        return null;
    }
}

async function downloadVideo(drive, fileId, filename) {
    const dest = path.join(CACHE_DIR, filename);

    const res = await drive.files.get(
        { fileId, alt: 'media' },
        { responseType: 'arraybuffer' },
    );

    fs.writeFileSync(dest, Buffer.from(res.data));
    log(`   📥 Downloaded: ${filename} (${(Buffer.from(res.data).length / 1024 / 1024).toFixed(1)}MB)`);
    return dest;
}

async function moveToPosted(drive, fileId) {
    if (!POSTED_FOLDER_ID) {
        log('   ⚠️ No GDRIVE_POSTED_FOLDER_ID set — skipping move');
        return;
    }

    await drive.files.update({
        fileId,
        addParents: POSTED_FOLDER_ID,
        removeParents: QUEUE_FOLDER_ID,
    });
    log(`   📁 Moved to posted folder`);
}

// ── Instagram Publishing ─────────────────────────────────────────────────────

async function uploadToTempHost(videoPath) {
    // Use the existing instagram-client temp host upload
    const { default: igClient } = await import('../src/instagram-client.js');
    return igClient.uploadToTempHost(videoPath);
}

async function postInstagramReel(caption, videoUrl) {
    log('📸 Posting Reel to Instagram...');

    // Step 1: Create media container
    const createParams = new URLSearchParams({
        media_type: 'REELS',
        video_url: videoUrl,
        caption,
        access_token: IG_TOKEN,
    });

    const createRes = await fetch(`${IG_API_BASE}/${IG_USER_ID}/media`, {
        method: 'POST',
        body: createParams,
    });
    const createData = await createRes.json();
    if (createData.error) throw new Error(`IG container failed: ${createData.error.message}`);

    const containerId = createData.id;
    log(`   Container: ${containerId}`);

    // Step 2: Wait for processing
    for (let i = 0; i < 30; i++) {
        await sleep(10000);
        const statusRes = await fetch(
            `${IG_API_BASE}/${containerId}?fields=status_code&access_token=${IG_TOKEN}`
        );
        const statusData = await statusRes.json();

        if (statusData.status_code === 'FINISHED') break;
        if (statusData.status_code === 'ERROR') {
            throw new Error(`IG processing error: ${JSON.stringify(statusData)}`);
        }
        log(`   Processing: ${statusData.status_code} (${(i + 1) * 10}s)`);
    }

    // Step 3: Publish
    const publishRes = await fetch(`${IG_API_BASE}/${IG_USER_ID}/media_publish`, {
        method: 'POST',
        body: new URLSearchParams({
            creation_id: containerId,
            access_token: IG_TOKEN,
        }),
    });
    const publishData = await publishRes.json();
    if (publishData.error) throw new Error(`IG publish failed: ${publishData.error.message}`);

    log(`🎉 Reel posted! Media ID: ${publishData.id}`);
    return publishData.id;
}

// ── Generate Full Caption from Seed ──────────────────────────────────────────

async function generateCaption(captionSeed, pillar) {
    const { generateText } = await import('../src/llm-client.js');

    const { text } = await generateText({
        prompt: `You write Instagram captions for Ghost — the face of Ghost AI Systems. Ghost is a military veteran turned AI systems architect. He speaks with Marine Corps drill sergeant authority.

Write an Instagram Reel caption based on this seed idea:
"${captionSeed}"

Content pillar: ${pillar}

Rules:
- HOOK FIRST: Bold opening line that stops the scroll
- Short paragraphs with line breaks
- 500-1200 characters total
- 1-2 emojis max (🔥 💀 👻)
- NO hashtags in caption body
- End with engagement: question or powerful one-liner
- Sound like a drill instructor who codes, not a brand

Return ONLY the caption text.`,
        maxOutputTokens: 500,
    });

    return text.trim();
}

// ── Main ─────────────────────────────────────────────────────────────────────

async function main() {
    log('');
    log('═══════════════════════════════════════════════');
    log('📺 DRIVE REEL PUBLISHER');
    log(`   Mode: ${DRY_RUN ? 'DRY RUN' : LIST_ONLY ? 'LIST' : 'LIVE'}`);
    log('═══════════════════════════════════════════════');

    if (!QUEUE_FOLDER_ID) {
        log('❌ GDRIVE_QUEUE_FOLDER_ID not set');
        process.exit(1);
    }

    const drive = await getDriveClient();
    const queued = await listQueuedVideos(drive);

    log(`\n📋 Queue: ${queued.length} videos`);
    for (const v of queued) {
        const marker = v.isToday ? '→' : ' ';
        log(`  ${marker} ${v.name} (${(v.size / 1024 / 1024).toFixed(1)}MB) [${v.scheduledDate}]`);
    }

    if (LIST_ONLY) return;

    // Find today's videos
    const todayVideos = queued.filter(v => v.isToday);
    if (todayVideos.length === 0) {
        log('\n⏸️ No videos scheduled for today');
        return;
    }

    log(`\n🎯 ${todayVideos.length} video(s) scheduled for today`);

    for (const video of todayVideos) {
        log(`\n${'─'.repeat(50)}`);
        log(`🎬 Publishing: ${video.name}`);

        try {
            // Get metadata
            const meta = await getMetadata(drive, video);
            const pillar = meta?.pillar || 'drill';
            const captionSeed = meta?.caption_seed || 'Discipline beats talent. Wake up and build.';

            // Generate full caption from seed
            log('   ✍️ Generating caption...');
            const caption = await generateCaption(captionSeed, pillar);
            log(`   Caption: "${caption.substring(0, 80)}..."`);

            if (DRY_RUN) {
                log('   👁️ DRY RUN — skipping publish');
                continue;
            }

            // Download video from Drive
            const localPath = await downloadVideo(drive, video.id, video.name);

            // Upload to temp host for public URL
            log('   📤 Uploading to temp host...');
            const publicUrl = await uploadToTempHost(localPath);
            log(`   URL: ${publicUrl}`);

            // Post to Instagram
            await postInstagramReel(caption, publicUrl);

            // Move to posted folder
            await moveToPosted(drive, video.id);
            if (meta?.metaFileId) {
                await moveToPosted(drive, meta.metaFileId);
            }

            // Cleanup local cache
            if (fs.existsSync(localPath)) fs.unlinkSync(localPath);

        } catch (err) {
            log(`   ❌ FAILED: ${err.message}`);
        }
    }

    log('\n✅ Publisher run complete');
}

main().catch(err => {
    log(`💥 Fatal: ${err.message}`);
    process.exit(1);
});
